UPDATE group_link
SET deleted_at = NULL,
    group_name = COALESCE(NULLIF(TRIM(#{groupName}), ''), group_name),
    membership_state = CASE WHEN membership_state = 3 THEN 3 ELSE 2 END,
    updated_at = #{updatedAt}
WHERE id = #{groupLinkId}

UPDATE account_group_membership
SET deleted_at = #{deletedAt},
    updated_at = #{deletedAt}
WHERE account_id = #{accountId}
  AND deleted_at IS NULL

  AND group_jid NOT IN
  #{jid}
